beginning.embedded_functions:
#include <string.h>

static inline int em_is_ur_port(double port) {
    int p = (int)port;
    // UR Dashboard Server port
    if (p == 29999) return 1;
    // UR Primary interface port
    if (p == 30001) return 1;
    // UR Secondary/Real-time interface port
    if (p == 30002) return 1;
    return 0;
}

static inline int em_check_ur_dashboard_cmd(const char *payload) {
    if (payload == NULL) return 0;

    // Dangerous UR dashboard commands
    static const char *commands[] = {
        "load ",
        "play\n",
        "play\r",
        "power on",
        "power off",
        "brake release",
        "shutdown",
        "unlock protective stop",
        "close safety popup",
        "restart safety",
        "load installation",
        "quit\n",
        "quit\r",
        "stop\n",
        "stop\r"
    };
    static const int num_commands = sizeof(commands) / sizeof(commands[0]);

    int i;
    for (i = 0; i < num_commands; i++) {
        if (strstr(payload, commands[i]) != NULL) {
            return 1;
        }
    }

    return 0;
}
